import{_ as e,o as l,c as n,ag as a}from"./chunks/framework.BZohXCq9.js";const y=JSON.parse('{"title":"Trạng thái triển khai Web (travel-web)","description":"","frontmatter":{},"headers":[],"relativePath":"05-quan-ly-sprint/trang-thai-web.md","filePath":"05-quan-ly-sprint/trang-thai-web.md"}'),i={name:"05-quan-ly-sprint/trang-thai-web.md"};function d(r,t,o,s,g,h){return l(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="trang-thai-trien-khai-web-travel-web" tabindex="-1">Trạng thái triển khai Web (<code>travel-web</code>) <a class="header-anchor" href="#trang-thai-trien-khai-web-travel-web" aria-label="Permalink to &quot;Trạng thái triển khai Web (`travel-web`)&quot;">​</a></h1><blockquote><p><strong>Cập nhật:</strong> 30/05/2026 — sau khi renumber sprint (Option B) và drop Loyalty khỏi MVP. Sprint 4 = Schema Pivot (NOW). Tích điểm thành viên defer Phase 2.</p></blockquote><p>Tài liệu này là <strong>nguồn sự thật</strong> về tiến độ code web. Khi hoàn thành tính năng mới, cập nhật file này trước khi đóng sprint.</p><h2 id="tong-quan-sprint" tabindex="-1">Tổng quan sprint <a class="header-anchor" href="#tong-quan-sprint" aria-label="Permalink to &quot;Tổng quan sprint&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Sprint</th><th style="text-align:left;">Trạng thái</th><th style="text-align:left;">Tiến độ web</th><th style="text-align:left;">Effort</th><th style="text-align:left;">Ghi chú</th></tr></thead><tbody><tr><td style="text-align:left;">Sprint 1 — Nền tảng</td><td style="text-align:left;">✅ Done</td><td style="text-align:left;">100%</td><td style="text-align:left;">2 tuần</td><td style="text-align:left;">Auth, middleware, profile, dual cookie</td></tr><tr><td style="text-align:left;">Sprint 2 — CMS &amp; Điểm đến</td><td style="text-align:left;">✅ Done</td><td style="text-align:left;">~95%</td><td style="text-align:left;">3 tuần</td><td style="text-align:left;">Destination CRUD, Cloudinary, Home Builder</td></tr><tr><td style="text-align:left;">Sprint 3 — Khám phá &amp; Tìm kiếm</td><td style="text-align:left;">⏸ Pause</td><td style="text-align:left;">~40%</td><td style="text-align:left;">đã 2 tuần</td><td style="text-align:left;">Pause để chạy Sprint 4. 60% còn lại đẩy sang Sprint 5</td></tr><tr><td style="text-align:left;"><strong>Sprint 4 — Schema Pivot</strong></td><td style="text-align:left;">🔥 <strong>NOW</strong></td><td style="text-align:left;">0%</td><td style="text-align:left;">2 tuần</td><td style="text-align:left;">Refactor schema + booking core theo ADR-001..006</td></tr><tr><td style="text-align:left;">Sprint 5 — Đóng Tìm kiếm</td><td style="text-align:left;">⏳ Upcoming</td><td style="text-align:left;">0%</td><td style="text-align:left;">1.5 tuần</td><td style="text-align:left;">Autocomplete + filter rating + cluster map</td></tr><tr><td style="text-align:left;">Sprint 6 — Đặt tour &amp; Thanh toán</td><td style="text-align:left;">⏳ Upcoming</td><td style="text-align:left;">~10%</td><td style="text-align:left;">3 tuần</td><td style="text-align:left;"><code>BookingService</code> skeleton có sẵn, đợi Sprint 4</td></tr><tr><td style="text-align:left;">Sprint 7 — Đánh giá khách</td><td style="text-align:left;">⏳ Upcoming</td><td style="text-align:left;">0%</td><td style="text-align:left;">1.5 tuần</td><td style="text-align:left;">Review + moderation (drop Loyalty → Phase 2)</td></tr><tr><td style="text-align:left;">Sprint 8 — Báo cáo + SEO + Launch</td><td style="text-align:left;">⏳ Upcoming</td><td style="text-align:left;">~15%</td><td style="text-align:left;">2 tuần</td><td style="text-align:left;">Sitemap, SEO metadata đã có; thêm L0 Dashboard, perf tuning</td></tr></tbody></table><p><strong>Tổng còn lại tới launch MVP</strong>: ~10 tuần ≈ 2.5 tháng.</p><hr><h2 id="sprint-1-—-nen-tang-done" tabindex="-1">Sprint 1 — Nền tảng (Done) <a class="header-anchor" href="#sprint-1-—-nen-tang-done" aria-label="Permalink to &quot;Sprint 1 — Nền tảng (Done)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Hạng mục</th><th style="text-align:left;">Web</th></tr></thead><tbody><tr><td style="text-align:left;">Prisma schema + migrations</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Supabase Auth + <code>@supabase/ssr</code></td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Middleware phân tách Admin (<code>/portal/*</code>) / Public</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Service layer (<code>AuthService</code>, …)</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Admin login + role <code>ADMIN</code></td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Dual cookie session (<code>AUTH_COOKIES.ADMIN</code> / <code>PUBLIC</code>)</td><td style="text-align:left;">✅</td></tr></tbody></table><hr><h2 id="sprint-2-—-quan-tri-noi-dung-điem-đen-done" tabindex="-1">Sprint 2 — Quản trị nội dung &amp; Điểm đến (Done) <a class="header-anchor" href="#sprint-2-—-quan-tri-noi-dung-điem-đen-done" aria-label="Permalink to &quot;Sprint 2 — Quản trị nội dung &amp; Điểm đến (Done)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Task</th><th style="text-align:left;">Web</th><th style="text-align:left;">Ghi chú</th></tr></thead><tbody><tr><td style="text-align:left;">SP2-01 CRUD Điểm đến</td><td style="text-align:left;">✅</td><td style="text-align:left;"><code>admin/destinations</code>, Server Actions</td></tr><tr><td style="text-align:left;">SP2-02 Cloudinary upload</td><td style="text-align:left;">✅</td><td style="text-align:left;">Gallery điểm đến; AC nâng cao (WebP batch, progress) <strong>chưa</strong></td></tr><tr><td style="text-align:left;">SP2-03 Vùng miền (Regions)</td><td style="text-align:left;">✅</td><td style="text-align:left;"><strong>3 miền cố định</strong> — seed <code>mb</code>/<code>mt</code>/<code>mn</code>, <strong>không</strong> CRUD admin</td></tr><tr><td style="text-align:left;">SP2-05 Validation &amp; Toast</td><td style="text-align:left;">✅</td><td style="text-align:left;">Admin forms</td></tr><tr><td style="text-align:left;">SP2-06 Cài đặt hệ thống</td><td style="text-align:left;">✅</td><td style="text-align:left;">System + SEO settings, Home Builder</td></tr><tr><td style="text-align:left;">Home Builder modules</td><td style="text-align:left;">✅</td><td style="text-align:left;">Trending, map, collections, …</td></tr><tr><td style="text-align:left;">Dynamic sitemap</td><td style="text-align:left;">✅</td><td style="text-align:left;"><code>src/app/sitemap.ts</code></td></tr></tbody></table><h3 id="vung-mien-regions-—-quyet-đinh-san-pham" tabindex="-1">Vùng miền (Regions) — quyết định sản phẩm <a class="header-anchor" href="#vung-mien-regions-—-quyet-đinh-san-pham" aria-label="Permalink to &quot;Vùng miền (Regions) — quyết định sản phẩm&quot;">​</a></h3><ul><li>Bảng <code>regions</code> trong DB: <strong>Miền Bắc</strong>, <strong>Miền Trung</strong>, <strong>Miền Nam</strong> (<code>prisma/seed.ts</code>).</li><li>Admin <strong>chọn</strong> vùng khi tạo điểm đến (<code>getRegionsAction</code>); <strong>không</strong> có màn CRUD thêm/sửa/xóa miền.</li><li>Không triển khai <code>POST/PUT/DELETE /api/v1/regions</code> (xem <a href="./sprint-2-quan-tri-diem-den/05-api-design">API Design</a>).</li></ul><hr><h2 id="sprint-3-—-kham-pha-tim-kiem-pause" tabindex="-1">Sprint 3 — Khám phá &amp; Tìm kiếm (Pause) <a class="header-anchor" href="#sprint-3-—-kham-pha-tim-kiem-pause" aria-label="Permalink to &quot;Sprint 3 — Khám phá &amp; Tìm kiếm (Pause)&quot;">​</a></h2><blockquote><p><strong>Trạng thái</strong>: Đã làm 40%, paused để chạy Sprint 4. Việc còn lại sẽ làm ở Sprint 5.</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">Task</th><th style="text-align:left;">Web</th><th style="text-align:left;">Ghi chú</th></tr></thead><tbody><tr><td style="text-align:left;">SP3-01 UI Discovery</td><td style="text-align:left;">🔶</td><td style="text-align:left;">Trang <code>/diem-den</code>, <code>/tours</code>, Home modules — đã có</td></tr><tr><td style="text-align:left;">SP3-02 Search Autocomplete</td><td style="text-align:left;">❌</td><td style="text-align:left;">→ Sprint 5</td></tr><tr><td style="text-align:left;">SP3-03 Filter động</td><td style="text-align:left;">🔶</td><td style="text-align:left;">Cơ bản có; cần thêm rating + tourType — Sprint 5</td></tr><tr><td style="text-align:left;">SP3-04 Interactive Map</td><td style="text-align:left;">🔶</td><td style="text-align:left;">Embed/link có; cluster — Sprint 5</td></tr><tr><td style="text-align:left;">SP3-05 API Search</td><td style="text-align:left;">🔶</td><td style="text-align:left;"><code>TourService.searchListings</code>, API <code>GET /api/v1/tours</code> — đã có</td></tr><tr><td style="text-align:left;">Quản lý Tour (admin + public)</td><td style="text-align:left;">✅</td><td style="text-align:left;">Đã có trước backlog SP3 — sẽ refactor Pattern C ở Sprint 4</td></tr></tbody></table><hr><h2 id="🔥-sprint-4-—-schema-pivot-now" tabindex="-1">🔥 Sprint 4 — Schema Pivot (NOW) <a class="header-anchor" href="#🔥-sprint-4-—-schema-pivot-now" aria-label="Permalink to &quot;🔥 Sprint 4 — Schema Pivot (NOW)&quot;">​</a></h2><blockquote><p><strong>Lý do</strong>: audit code phát hiện schema <code>travel-web</code> lệch 7 chỗ với ADR-001..006. Phải pivot trước Sprint 6 Booking. <strong>Kế hoạch</strong>: 2 tuần (10 ngày làm việc), 7 stories. <strong>Doc spec</strong>: <code>sprint-4-schema-pivot/{00-tong-quan,01-stories,02-runbook,03-test-plan,04-wireframes}.md</code></p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">Story</th><th style="text-align:left;">Effort</th><th style="text-align:left;">Trạng thái</th></tr></thead><tbody><tr><td style="text-align:left;">S4-01 Apply migration <code>add_pricing_options_and_allotment</code> (10 PARTs)</td><td style="text-align:left;">2 ngày</td><td style="text-align:left;">❌ Chưa start</td></tr><tr><td style="text-align:left;">S4-02 Drop HotelBooking + bookingType refs</td><td style="text-align:left;">0.5 ngày</td><td style="text-align:left;">❌</td></tr><tr><td style="text-align:left;">S4-03 Refactor Tour CRUD theo Pricing Pattern C</td><td style="text-align:left;">2-3 ngày</td><td style="text-align:left;">❌</td></tr><tr><td style="text-align:left;">S4-04 Refactor BookingService Pattern C</td><td style="text-align:left;">1-2 ngày</td><td style="text-align:left;">❌</td></tr><tr><td style="text-align:left;">S4-05 Booking widget multi-pax</td><td style="text-align:left;">2-3 ngày</td><td style="text-align:left;">❌</td></tr><tr><td style="text-align:left;">S4-06 InquiryRequest (Series + Private split)</td><td style="text-align:left;">1-2 ngày</td><td style="text-align:left;">❌</td></tr><tr><td style="text-align:left;">S4-07 Doc sync + sprint pivot logging</td><td style="text-align:left;">0.5 ngày</td><td style="text-align:left;">❌</td></tr></tbody></table><p><strong>Pre-req checklist trước Day 1</strong>:</p><ul><li>[ ] Supabase Pro plan + PITR enabled trên prod</li><li>[ ] Tạo Supabase staging project mới</li><li>[ ] Dump prod + import staging (≤24h trước Day 1)</li><li>[ ] Pre-flight audit pass trên staging (6 SQL check)</li><li>[ ] Vercel preview deployment cho branch <code>sprint-4/migration-pivot</code></li><li>[ ] Wireframe Booking widget reviewed (xem <code>sprint-4-schema-pivot/04-wireframes.md</code>)</li></ul><hr><h2 id="sprint-5-—-đong-tim-kiem-upcoming" tabindex="-1">Sprint 5 — Đóng Tìm kiếm (Upcoming) <a class="header-anchor" href="#sprint-5-—-đong-tim-kiem-upcoming" aria-label="Permalink to &quot;Sprint 5 — Đóng Tìm kiếm (Upcoming)&quot;">​</a></h2><blockquote><p>Tiếp nối 60% còn lại của Sprint 3. Spec: <code>sprint-5-dong-tim-kiem/00-tong-quan.md</code>.</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">Story</th><th style="text-align:left;">Effort</th><th style="text-align:left;">Trạng thái</th></tr></thead><tbody><tr><td style="text-align:left;">S5-01 Search autocomplete</td><td style="text-align:left;">3 ngày</td><td style="text-align:left;">❌</td></tr><tr><td style="text-align:left;">S5-02 Filter rating + tourType + price + duration</td><td style="text-align:left;">2 ngày</td><td style="text-align:left;">❌</td></tr><tr><td style="text-align:left;">S5-03 Cluster map</td><td style="text-align:left;">2-3 ngày</td><td style="text-align:left;">❌</td></tr></tbody></table><hr><h2 id="sprint-6-—-đat-tour-thanh-toan-upcoming" tabindex="-1">Sprint 6 — Đặt tour &amp; Thanh toán (Upcoming) <a class="header-anchor" href="#sprint-6-—-đat-tour-thanh-toan-upcoming" aria-label="Permalink to &quot;Sprint 6 — Đặt tour &amp; Thanh toán (Upcoming)&quot;">​</a></h2><blockquote><p>Spec cũ ở <code>sprint-6-dat-cho-thanh-toan/</code> (rename từ &quot;sprint-4&quot; cũ — sẽ được audit + update theo schema mới ở task S4-07).</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">Task</th><th style="text-align:left;">Web</th><th style="text-align:left;">Ghi chú</th></tr></thead><tbody><tr><td style="text-align:left;">Booking flow E2E (login → multi-pax → checkout → payment)</td><td style="text-align:left;">❌</td><td style="text-align:left;">Tích hợp các thành phần đã có ở Sprint 4</td></tr><tr><td style="text-align:left;">VNPay integration</td><td style="text-align:left;">❌</td><td style="text-align:left;">Webhook, signature verification</td></tr><tr><td style="text-align:left;">MoMo integration</td><td style="text-align:left;">❌</td><td style="text-align:left;">(optional, ưu tiên VNPay)</td></tr><tr><td style="text-align:left;">Email confirm booking (Resend)</td><td style="text-align:left;">❌</td><td style="text-align:left;">Template <code>booking-confirmed.tsx</code></td></tr><tr><td style="text-align:left;">Cron auto-cancel quá deadline 15 phút</td><td style="text-align:left;">❌</td><td style="text-align:left;">Vercel Cron + service <code>BookingService.cancelExpired()</code></td></tr><tr><td style="text-align:left;">Admin OMS (Order Management) update status</td><td style="text-align:left;">🔶</td><td style="text-align:left;">List đọc-only đã có; cần action duyệt/hủy</td></tr><tr><td style="text-align:left;"><code>/don-dat</code> của user</td><td style="text-align:left;">🔶</td><td style="text-align:left;">Placeholder; cần list booking + detail</td></tr></tbody></table><hr><h2 id="sprint-7-—-đanh-gia-khach-upcoming" tabindex="-1">Sprint 7 — Đánh giá khách (Upcoming) <a class="header-anchor" href="#sprint-7-—-đanh-gia-khach-upcoming" aria-label="Permalink to &quot;Sprint 7 — Đánh giá khách (Upcoming)&quot;">​</a></h2><blockquote><p>Drop Loyalty (tích điểm thành viên) — defer Phase 2.</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">Task</th><th style="text-align:left;">Web</th><th style="text-align:left;">Ghi chú</th></tr></thead><tbody><tr><td style="text-align:left;">User submit review sau tour</td><td style="text-align:left;">❌</td><td style="text-align:left;">Form rating 1-5 + content + photos</td></tr><tr><td style="text-align:left;">Admin moderation (approve / reject)</td><td style="text-align:left;">❌</td><td style="text-align:left;">Filter PENDING, bulk action</td></tr><tr><td style="text-align:left;">Review hiển thị trên tour detail</td><td style="text-align:left;">❌</td><td style="text-align:left;">Pagination, sort by rating</td></tr><tr><td style="text-align:left;">JSON-LD <code>aggregateRating</code></td><td style="text-align:left;">❌</td><td style="text-align:left;">SEO Schema.org Review</td></tr><tr><td style="text-align:left;">Verified review (chỉ user đã đặt tour mới review được)</td><td style="text-align:left;">❌</td><td style="text-align:left;">Check <code>Booking.userId</code></td></tr></tbody></table><hr><h2 id="sprint-8-—-bao-cao-seo-launch-upcoming" tabindex="-1">Sprint 8 — Báo cáo + SEO + Launch (Upcoming) <a class="header-anchor" href="#sprint-8-—-bao-cao-seo-launch-upcoming" aria-label="Permalink to &quot;Sprint 8 — Báo cáo + SEO + Launch (Upcoming)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Task</th><th style="text-align:left;">Web</th><th style="text-align:left;">Ghi chú</th></tr></thead><tbody><tr><td style="text-align:left;">Admin Dashboard L0 (operational)</td><td style="text-align:left;">❌</td><td style="text-align:left;">Đơn hôm nay, doanh thu tuần, top tour, export CSV (xem ADR-007)</td></tr><tr><td style="text-align:left;">SEO finalize</td><td style="text-align:left;">🔶</td><td style="text-align:left;">Sitemap có; cần meta description + OG image cho mọi page</td></tr><tr><td style="text-align:left;">Performance optimize</td><td style="text-align:left;">❌</td><td style="text-align:left;">Image optimization, lazy load, bundle size</td></tr><tr><td style="text-align:left;">Launch checklist</td><td style="text-align:left;">❌</td><td style="text-align:left;">Domain, SSL, monitoring, backup, fanpage announce</td></tr></tbody></table><hr><h2 id="auth-khach-hang-bo-sung-ngoai-sprint-cu" tabindex="-1">Auth khách hàng (bổ sung ngoài sprint cũ) <a class="header-anchor" href="#auth-khach-hang-bo-sung-ngoai-sprint-cu" aria-label="Permalink to &quot;Auth khách hàng (bổ sung ngoài sprint cũ)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Tính năng</th><th style="text-align:left;">Web</th></tr></thead><tbody><tr><td style="text-align:left;">Đăng ký / đăng nhập email</td><td style="text-align:left;">✅ <code>/dang-ky</code>, <code>/dang-nhap</code></td></tr><tr><td style="text-align:left;">Xác nhận email + gửi lại</td><td style="text-align:left;">✅ <code>/dang-ky/xac-nhan-email</code></td></tr><tr><td style="text-align:left;">Quên / đặt lại mật khẩu</td><td style="text-align:left;">✅ <code>/quen-mat-khau</code>, <code>/dat-lai-mat-khau</code></td></tr><tr><td style="text-align:left;">Đăng nhập Google OAuth</td><td style="text-align:left;">✅ Supabase + <code>/auth/callback</code></td></tr><tr><td style="text-align:left;">Đồng bộ profile Prisma</td><td style="text-align:left;">✅ <code>ensureUserProfile</code> (tên, avatar Google)</td></tr><tr><td style="text-align:left;">Tài khoản <code>/tai-khoan</code></td><td style="text-align:left;">🔶 Xem thông tin; sửa profile <strong>chưa</strong></td></tr><tr><td style="text-align:left;">Đơn của tôi <code>/don-dat</code></td><td style="text-align:left;">🔶 Placeholder sau khi đăng nhập</td></tr></tbody></table><p>Chi tiết: <a href="./../04-phat-trien/04-bao-mat-xac-thuc">Bảo mật &amp; Xác thực</a>.</p><hr><h2 id="defer-phase-2-sau-khi-launch-mvp" tabindex="-1">Defer Phase 2 (sau khi launch MVP) <a class="header-anchor" href="#defer-phase-2-sau-khi-launch-mvp" aria-label="Permalink to &quot;Defer Phase 2 (sau khi launch MVP)&quot;">​</a></h2><ul><li><strong>Tích điểm thành viên</strong> (Loyalty) — tier, points, redeem voucher → defer (build sau khi có 100-200 khách thật)</li><li><strong>Mobile app</strong> — React Native hoặc Flutter</li><li><strong>L1/L2 reporting nâng cao</strong> — conversion funnel, AOV, CAC, P&amp;L</li><li><strong>Voice search / Image search</strong></li><li><strong>Saved searches / search history per user</strong></li><li><strong>CMS pháp lý admin</strong> (<code>LegalContent</code>) — hiện tại trang public tĩnh i18n</li><li><strong>Advanced map</strong> — heatmap, custom layer</li></ul><hr><h2 id="đa-quyet-đinh-drop-khoi-mvp" tabindex="-1">Đã quyết định drop khỏi MVP <a class="header-anchor" href="#đa-quyet-đinh-drop-khoi-mvp" aria-label="Permalink to &quot;Đã quyết định drop khỏi MVP&quot;">​</a></h2><ul><li><s>Hotel booking riêng lẻ <code>/khach-san</code></s> — ADR-001 (Hotel = content reference, không bookable)</li><li><s>Newsletter backend</s> — không quan trọng MVP, dùng form Mailchimp embed sau</li></ul><hr><p><em>Ký hiệu: ✅ hoàn thành · 🔶 một phần · ❌ chưa có</em></p>',51)])])}const f=e(i,[["render",d]]);export{y as __pageData,f as default};
